type Result[T any] struct {
    Value T
    Error error
}

func SafeDivide(a, b float64) Result[float64] {
    if b == 0 {
        return Result[float64]{Error: errors.New("division by zero")}
    }
    return Result[float64]{Value: a / b}
}

func QuickSort(arr []int) []int {
    if len(arr) <= 1 {
        return arr
    }
    pivot := arr[len(arr)/2]
    left := []int{}
    middle := []int{}
    right := []int{}
    for _, v := range arr {
        if v < pivot {
            left = append(left, v)
        } else if v == pivot {
            middle = append(middle, v)
        } else {
            right = append(right, v)
        }
    }
    return append(append(QuickSort(left), middle...), QuickSort(right)...)
}

type Pool struct {
    workers int
    jobs    chan func()
    wg      sync.WaitGroup
}

func NewPool(workers int) *Pool {
    p := &Pool{
        workers: workers,
        jobs:    make(chan func(), 100),
    }
    for i := 0; i < workers; i++ {
        go p.worker()
    }
    return p
}

func (p *Pool) worker() {
    for job := range p.jobs {
        job()
        p.wg.Done()
    }
}

func BinarySearch(arr []int, target int) int {
    left, right := 0, len(arr)-1
    for left <= right {
        mid := left + (right-left)/2
        if arr[mid] == target {
            return mid
        } else if arr[mid] < target {
            left = mid + 1
        } else {
            right = mid - 1
        }
    }
    return -1
}

type Option[T any] struct {
    value T
    valid bool
}

func Some[T any](v T) Option[T] {
    return Option[T]{value: v, valid: true}
}

func None[T any]() Option[T] {
    return Option[T]{valid: false}
}

func (o Option[T]) Get() (T, bool) {
    return o.value, o.valid
}

func MergeSort(arr []int) []int {
    if len(arr) <= 1 {
        return arr
    }
    mid := len(arr) / 2
    left := MergeSort(arr[:mid])
    right := MergeSort(arr[mid:])
    return merge(left, right)
}

func merge(left, right []int) []int {
    result := make([]int, 0, len(left)+len(right))
    i, j := 0, 0
    for i < len(left) && j < len(right) {
        if left[i] <= right[j] {
            result = append(result, left[i])
            i++
        } else {
            result = append(result, right[j])
            j++
        }
    }
    return append(result, append(left[i:], right[j:]...)...)
}

type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

func InorderTraversal(root *TreeNode) []int {
    result := []int{}
    var traverse func(*TreeNode)
    traverse = func(node *TreeNode) {
        if node != nil {
            traverse(node.Left)
            result = append(result, node.Val)
            traverse(node.Right)
        }
    }
    traverse(root)
    return result
}

func Memoize(fn func(int) int) func(int) int {
    cache := make(map[int]int)
    return func(n int) int {
        if val, ok := cache[n]; ok {
            return val
        }
        result := fn(n)
        cache[n] = result
        return result
    }
}

type Middleware func(http.Handler) http.Handler

func LoggingMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        log.Printf("%s %s %v", r.Method, r.URL.Path, time.Since(start))
    })
}

func Retry[T any](fn func() (T, error), maxAttempts int, delay time.Duration) (T, error) {
    var lastErr error
    var result T
    for i := 0; i < maxAttempts; i++ {
        result, lastErr = fn()
        if lastErr == nil {
            return result, nil
        }
        time.Sleep(delay * time.Duration(i+1))
    }
    return result, lastErr
}

func Flatten[T any](nested [][]T) []T {
    result := make([]T, 0)
    for _, slice := range nested {
        result = append(result, slice...)
    }
    return result
}

type Iterator[T any] interface {
    Next() bool
    Value() T
}

type SliceIterator[T any] struct {
    data  []T
    index int
}

func (it *SliceIterator[T]) Next() bool {
    return it.index < len(it.data)
}

func (it *SliceIterator[T]) Value() T {
    val := it.data[it.index]
    it.index++
    return val
}

func Debounce[T any](fn func(T), delay time.Duration) func(T) {
    var timer *time.Timer
    return func(arg T) {
        if timer != nil {
            timer.Stop()
        }
        timer = time.AfterFunc(delay, func() {
            fn(arg)
        })
    }
}
